import{_ as t,o as a,c as s,a2 as r}from"./chunks/framework.BFZItJIV.js";const u=JSON.parse('{"title":"Benchmarks","description":"TalaDB performance benchmarks — document write throughput, indexed query latency, and on-device vector search timings, measured with the open-source suite in scripts/bench.mjs.","frontmatter":{"title":"Benchmarks","description":"TalaDB performance benchmarks — document write throughput, indexed query latency, and on-device vector search timings, measured with the open-source suite in scripts/bench.mjs."},"headers":[],"relativePath":"benchmarks.md","filePath":"benchmarks.md"}'),d={name:"benchmarks.md"};function o(n,e,i,c,l,h){return a(),s("div",null,[...e[0]||(e[0]=[r(`<h1 id="benchmarks" tabindex="-1">Benchmarks <a class="header-anchor" href="#benchmarks" aria-label="Permalink to &quot;Benchmarks&quot;">​</a></h1><p>Real numbers, measured honestly. All results below come from the benchmark suite that ships in the repository — <a href="https://github.com/thinkgrid-labs/taladb/blob/main/scripts/bench.mjs" target="_blank" rel="noreferrer"><code>scripts/bench.mjs</code></a> — so you can reproduce every row on your own hardware:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --filter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @taladb/node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # build the native module</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bench</span></span></code></pre></div><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td>TalaDB</td><td>v0.8.2 (<code>@taladb/node</code>, release build)</td></tr><tr><td>Machine</td><td>2018 MacBook Pro — Intel i5-8259U @ 2.30 GHz, 8 GB RAM</td></tr><tr><td>Runtime</td><td>Node.js v22, macOS (darwin x64)</td></tr><tr><td>Database</td><td>File-backed (the production configuration)</td></tr><tr><td>Date</td><td>2026-07-09</td></tr></tbody></table><p>The suite uses the raw N-API binding; the <code>taladb</code> wrapper adds only a thin async passthrough on Node.js. Latencies are the <strong>median</strong> of repeated timed iterations after warmup. Documents are realistic small records (~7 fields); vectors are 384-dimensional unit vectors — the output shape of <code>all-MiniLM-L6-v2</code>, the most common on-device embedding model.</p><p>This is deliberately modest hardware. On a recent Apple Silicon or desktop-class machine, expect meaningfully better numbers across the board.</p><h2 id="document-writes" tabindex="-1">Document writes <a class="header-anchor" href="#document-writes" aria-label="Permalink to &quot;Document writes&quot;">​</a></h2><p>File-backed, every operation durable on disk when the call returns.</p><table tabindex="0"><thead><tr><th>Operation</th><th>Detail</th><th>Result</th></tr></thead><tbody><tr><td><code>insert</code> (single doc)</td><td>one transaction per call</td><td><strong>~47 ops/s</strong></td></tr><tr><td><code>insertMany</code> (batch 100)</td><td>single transaction per batch</td><td><strong>~3.9k docs/s</strong></td></tr><tr><td><code>insertMany</code> (batch 1,000)</td><td>single transaction per batch</td><td><strong>~19k docs/s</strong></td></tr><tr><td><code>insertMany</code> (batch 5,000)</td><td>single transaction per batch</td><td><strong>~34k docs/s</strong></td></tr><tr><td><code>updateOne</code> (by <code>_id</code>)</td><td>point update, <code>$set</code> one field</td><td><strong>~47 ops/s</strong></td></tr><tr><td><code>deleteOne</code> (by <code>_id</code>)</td><td>point delete</td><td><strong>~46 ops/s</strong></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Batch your writes</p><p>Every individual write is a full ACID transaction — the ~47 ops/s ceiling for single-document calls is the cost of a durable commit to disk (redb <code>fsync</code>), not of TalaDB&#39;s write path. The same machine sustains <strong>34k docs/s</strong> when writes share a transaction. If you are inserting more than a handful of documents, use <code>insertMany</code>.</p></div><h2 id="query-latency-—-100-000-documents" tabindex="-1">Query latency — 100,000 documents <a class="header-anchor" href="#query-latency-—-100-000-documents" aria-label="Permalink to &quot;Query latency — 100,000 documents&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Operation</th><th>Detail</th><th>Result</th></tr></thead><tbody><tr><td><code>findOne</code> by <code>_id</code></td><td>primary-key point get</td><td><strong>23 µs</strong></td></tr><tr><td><code>find</code>, indexed equality</td><td>secondary index, ~10 matches</td><td><strong>167 µs</strong></td></tr><tr><td><code>find</code>, indexed range (<code>$gte</code>)</td><td>newest ~100 docs by <code>publishedAt</code></td><td><strong>1.4 ms</strong></td></tr><tr><td><code>find</code>, unindexed field</td><td>full scan of 100k docs</td><td><strong>434 ms</strong></td></tr><tr><td><code>count</code>, unindexed equality</td><td>scan, 12.5k matches</td><td><strong>461 ms</strong></td></tr></tbody></table><p>Point gets and indexed lookups stay in the microsecond range at 100k documents — the B-tree index layout gives <code>O(log n)</code> lookups regardless of collection size. Unindexed queries fall back to a full collection scan; if a field appears in your filters regularly, <code>createIndex</code> turns a 434 ms scan into a 167 µs lookup — a <strong>~2,600×</strong> difference.</p><div class="warning custom-block"><p class="custom-block-title">Two-sided ranges</p><p>The query planner is currently greedy rather than cost-based: a two-sided range (<code>$gte</code> + <code>$lt</code> on the same field) uses the index for the lower bound only and post-filters the rest, so it can scan far more index entries than the window contains (~449 ms for a ~100-doc window at 100k docs, versus 1.4 ms for the one-sided form). Bounded range plans are on the roadmap. Until then, prefer one-sided ranges on recent data, or an indexed equality alongside the range.</p></div><h2 id="vector-search-—-384-dim-cosine-top-10" tabindex="-1">Vector search — 384-dim, cosine, top-10 <a class="header-anchor" href="#vector-search-—-384-dim-cosine-top-10" aria-label="Permalink to &quot;Vector search — 384-dim, cosine, top-10&quot;">​</a></h2><p>Exact (brute-force) k-nearest-neighbour over all vectors — no approximation, no recall trade-off.</p><table tabindex="0"><thead><tr><th>Collection size</th><th><code>findNearest</code> (median)</th></tr></thead><tbody><tr><td>1,000 vectors</td><td><strong>4.0 ms</strong></td></tr><tr><td>10,000 vectors</td><td><strong>38 ms</strong></td></tr><tr><td>50,000 vectors</td><td><strong>188 ms</strong></td></tr><tr><td>100,000 vectors</td><td><strong>387 ms</strong></td></tr></tbody></table><p>Hybrid search — metadata pre-filter, then rank — costs roughly the same as pure vector search when the filter field is indexed:</p><table tabindex="0"><thead><tr><th>Operation</th><th>Detail</th><th>Result</th></tr></thead><tbody><tr><td><code>findNearest</code> + filter, 100k vectors</td><td>indexed pre-filter matching 10% of docs, then rank</td><td><strong>428 ms</strong></td></tr><tr><td>Vector ingest, 100k vectors</td><td><code>insertMany</code> with a live vector index</td><td><strong>~4.1k docs/s</strong></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Index your filter fields</p><p>The hybrid pre-filter is an ordinary document query, so it benefits from secondary indexes exactly like <code>find</code> does. In this suite, indexing the filter field brought filtered search from ~3 s down to 428 ms at 100k vectors.</p></div><p>For context: a typical on-device semantic search corpus (notes app, offline docs, chat history) is 1k–10k chunks, where exact search answers in <strong>under 40 ms</strong> — faster than a network round-trip to any cloud vector database, with zero data leaving the device.</p><h2 id="reading-these-numbers" tabindex="-1">Reading these numbers <a class="header-anchor" href="#reading-these-numbers" aria-label="Permalink to &quot;Reading these numbers&quot;">​</a></h2><ul><li><strong>Scaling</strong> — exact vector search is linear in collection size; document point lookups are logarithmic. Both behave predictably as your data grows.</li><li><strong>Latency floor, not ceiling</strong> — the test machine is a 2018 dual-fan ultrabook. Treat these as conservative.</li><li><strong>Browser and React Native</strong> — these figures are for the Node.js native module. The same Rust core runs in the browser (WASM + OPFS) and React Native (JSI), with platform-specific overheads; runtime-specific suites are planned.</li><li><strong>Methodology</strong> — deterministic seeded data, warmup before measurement, medians reported, one process, file-backed database. Read the ~250-line <a href="https://github.com/thinkgrid-labs/taladb/blob/main/scripts/bench.mjs" target="_blank" rel="noreferrer"><code>scripts/bench.mjs</code></a> for the exact workload.</li></ul>`,24)])])}const m=t(d,[["render",o]]);export{u as __pageData,m as default};
